  1	import * as React from 'react';
  2	import { CORSRule, GetBucketCorsCommandOutput } from '@aws-sdk/client-s3';
  3	import { DetailsItem } from '@odf/core/components/resource-pages/CommonDetails';
  4	import {
  5	  S3Provider,
  6	  S3Context,
  7	} from '@odf/core/components/s3-browser/s3-context';
  8	import { S3ProviderType } from '@odf/core/types';
  9	import { DASH } from '@odf/shared';
 10	import { StatusBox } from '@odf/shared/generic/status-box';
 11	import PageHeading from '@odf/shared/heading/page-heading';
 12	import { S3Commands } from '@odf/shared/s3';
 13	import { useCustomTranslation } from '@odf/shared/useCustomTranslationHook';
 14	import { deepSortObject } from '@odf/shared/utils';
 15	import { useModal } from '@openshift-console/dynamic-plugin-sdk';
 16	import { LaunchModal } from '@openshift-console/dynamic-plugin-sdk/lib/app/modal-support/ModalProvider';
 17	import * as _ from 'lodash-es';
 18	import { murmur3 } from 'murmurhash-js';
 19	import { TFunction } from 'react-i18next';
 20	import {
 21	  useParams,
 22	  useSearchParams,
 23	  useNavigate,
 24	  NavigateFunction,
 25	} from 'react-router-dom-v5-compat';
 26	import useSWR, { KeyedMutator } from 'swr';
 27	import {
 28	  TextContent,
 29	  Text,
 30	  TextVariants,
 31	  TextInput,
 32	  MenuToggle,
 33	} from '@patternfly/react-core';
 34	import {
 35	  ActionsColumn,
 36	  CustomActionsToggleProps,
 37	} from '@patternfly/react-table';
 38	import {
 39	  RULE_NAME,
 40	  RULE_HASH,
 41	  BUCKET_CORS_RULE_CACHE_KEY_SUFFIX,
 42	  BUCKETS_BASE_ROUTE,
 43	  getBucketOverviewBaseRoute,
 44	} from '../../../constants';
 45	import { isAllowAllConfig } from '../../../utils';
 46	import { getRowActions } from '../cors-rules-list/CORSRulesList';
 47	
 48	type CorsDetailsContentProps = { corsRule: CORSRule };
 49	
 50	const CustomActionsToggle = (props: CustomActionsToggleProps) => {
 51	  const { t } = useCustomTranslation();
 52	
 53	  return (
 54	    <MenuToggle
 55	      ref={props.toggleRef}
 56	      onClick={props.onToggle}
 57	      isDisabled={props.isDisabled}
 58	    >
 59	      {t('Actions')}
 60	    </MenuToggle>
 61	  );
 62	};
 63	
 64	const createCorsActions = (
 65	  t: TFunction<string>,
 66	  navigate: NavigateFunction,
 67	  launcher: LaunchModal,
 68	  mutate: KeyedMutator<GetBucketCorsCommandOutput>,
 69	  s3Client: S3Commands,
 70	  bucketName: string,
 71	  ruleName: string,
 72	  ruleHash: number
 73	) => {
 74	  return (
 75	    <ActionsColumn
 76	      items={getRowActions(
 77	        t,
 78	        navigate,
 79	        launcher,
 80	        mutate,
 81	        s3Client,
 82	        bucketName,
 83	        ruleName,
 84	        ruleHash,
 85	        true
 86	      )}
 87	      actionsToggle={CustomActionsToggle}
 88	    />
 89	  );
 90	};
 91	
 92	const CorsDetailsContent: React.FC<CorsDetailsContentProps> = ({
 93	  corsRule,
 94	}) => {
 95	  const { t } = useCustomTranslation();
 96	
 97	  const allOriginsAllowed = isAllowAllConfig(corsRule.AllowedOrigins);
 98	  const allHeadersAllowed = isAllowAllConfig(corsRule.AllowedHeaders);
 99	
100	  return (
101	    <div className="pf-v6-u-m-md">
102	      <DetailsItem field={t('Rule name')}>{corsRule.ID || DASH}</DetailsItem>
103	      <DetailsItem field={t('Allowed origins')}>
104	        {allOriginsAllowed
105	          ? t('All origins')
106	          : corsRule.AllowedOrigins.map((origin, index) => (
107	              <TextInput
108	                key={origin + index}
109	                value={origin}
110	                className="pf-v6-u-mb-xs pf-v6-u-w-50"
111	                isDisabled
112	              />
113	            ))}
114	      </DetailsItem>
115	      <DetailsItem field={t('Allowed methods')}>
116	        {corsRule.AllowedMethods.join(', ')}
117	      </DetailsItem>
118	      <DetailsItem field={t('Allowed headers')}>
119	        {allHeadersAllowed
120	          ? t('All headers')
121	          : corsRule.AllowedHeaders?.map((header, index) => (
122	              <TextInput
123	                key={header + index}
124	                value={header}
125	                className="pf-v6-u-mb-xs pf-v6-u-w-50"
126	                isDisabled
127	              />
128	            )) || DASH}
129	      </DetailsItem>
130	      <DetailsItem field={t('Exposed headers')}>
131	        {corsRule.ExposeHeaders?.map((exposedHeader, index) => (
132	          <TextInput
133	            key={exposedHeader + index}
134	            value={exposedHeader}
135	            className="pf-v6-u-mb-xs pf-v6-u-w-50"
136	            isDisabled
137	          />
138	        )) || DASH}
139	      </DetailsItem>
140	      <DetailsItem field={t('Max age for preflight requests (in seconds)')}>
141	        {corsRule.MaxAgeSeconds || DASH}
142	      </DetailsItem>
143	    </div>
144	  );
145	};
146	
147	const CorsDetails: React.FC = () => {
148	  const { t } = useCustomTranslation();
149	
150	  const launcher = useModal();
151	  const navigate = useNavigate();
152	
153	  const { bucketName } = useParams();
154	  const { s3Client } = React.useContext(S3Context);
155	  const [searchParams] = useSearchParams();
156	  const ruleName = searchParams.get(RULE_NAME);
157	  const ruleHash = searchParams.get(RULE_HASH);
158	  const providerType = s3Client.providerType as S3ProviderType;
159	
160	  const {
161	    data,
162	    isLoading,
163	    error: loadError,
164	    mutate,
165	  } = useSWR(
166	    `${s3Client.providerType}-${bucketName}-${BUCKET_CORS_RULE_CACHE_KEY_SUFFIX}`,
167	    () => s3Client.getBucketCors({ Bucket: bucketName }),
168	    {
169	      shouldRetryOnError: false,
170	    }
171	  );
172	
173	  const [corsRule, searchError] = React.useMemo(() => {
174	    if (!_.isEmpty(data)) {
175	      if (!!ruleName) {
176	        return [data.CORSRules?.find((rule) => rule.ID === ruleName), null];
177	      } else if (!!ruleHash) {
178	        // fallback if rule name (ID) is missing
179	        return [
180	          data.CORSRules?.find(
181	            (rule) =>
182	              `${murmur3(JSON.stringify(deepSortObject(rule)))}` === ruleHash
183	          ),
184	          null,
185	        ];
186	      }
187	      return [{} as CORSRule, Error('Rule not found')];
188	    }
189	
190	    return [{} as CORSRule, null];
191	  }, [data, ruleName, ruleHash]);
192	
193	  if (isLoading || loadError || searchError) {
194	    return (
195	      <StatusBox
196	        loaded={!isLoading}
197	        loadError={isLoading ? '' : loadError || searchError}
198	      />
199	    );
200	  }
201	
202	  return (
203	    <>
204	      <PageHeading
205	        breadcrumbs={[
206	          {
207	            name: t('Buckets'),
208	            path: BUCKETS_BASE_ROUTE,
209	          },
210	          {
211	            name: t('CORS'),
212	            path: `${getBucketOverviewBaseRoute(bucketName, providerType)}/permissions/cors`,
213	          },
214	          {
215	            name: t('CORS details'),
216	            path: '',
217	          },
218	        ]}
219	        title={
220	          !!ruleName ? (
221	            <TextContent>
222	              <Text component={TextVariants.h1}>{ruleName}</Text>
223	            </TextContent>
224	          ) : null
225	        }
226	        actions={() =>
227	          createCorsActions(
228	            t,
229	            navigate,
230	            launcher,
231	            mutate,
232	            s3Client,
233	            bucketName,
234	            ruleName,
235	            !!ruleHash ? Number(ruleHash) : null
236	          )
237	        }
238	        className="pf-v6-u-mt-md"
239	      />
240	      <CorsDetailsContent corsRule={corsRule} />
241	    </>
242	  );
243	};
244	
245	export const CorsDetailsPage: React.FC = () => (
246	  <S3Provider>
247	    <CorsDetails />
248	  </S3Provider>
249	);

